// ─────────────────────────────────────────────
// Parse incoming WhatsApp message + filter
// ─────────────────────────────────────────────
const body = $input.item.json.body || $input.item.json;
const msg = body.message || body;

// Extract core fields (UAZAPI shape)
const chatId = msg.chatid || msg.chat?.id || msg.from || '';
const messageId = msg.messageid || msg.id || '';
const senderName = msg.sender?.name || msg.pushname || msg.notifyName || 'Unknown';
const senderPhone = (msg.sender?.id || msg.author || msg.from || '').replace(/@.*/, '');
const rawText = msg.text || msg.body || msg.message?.conversation || msg.conversation || '';
const fromMe = !!msg.fromMe;
const isGroup = chatId.endsWith('@g.us');

// Skip own messages
if (fromMe) {
  return [{ json: { skip: true, reason: 'fromMe' } }];
}

// Group registry (kept in code as fast-path; jarvis_groups MySQL table is source of truth for new groups)
const GROUPS = {
  '120363426390515923@g.us': { context: 'angelfly', label: 'Angel Fly Marketing Geral' },
  '120363420996892188@g.us': { context: 'garlic',   label: 'Garlic N Lemon | Branding' },
  '120363422948599063@g.us': { context: 'ernesto',  label: 'Ernesto | Site & Identidade Visual' }
};
const group = GROUPS[chatId] || { context: 'unknown', label: 'Unknown' };

// Mention detection
const lower = String(rawText).toLowerCase();
const mentioned = /@\s*jarvis\b/.test(lower)
  || /\bjarvis\b/.test(lower)
  || (msg.mentioned_jid || []).some(j => String(j).includes('59739253801103'));

if (!mentioned) {
  return [{ json: { skip: true, reason: 'not_mentioned', chatId, messageId } }];
}

// Clean text — remove the @Jarvis token
const cleanText = String(rawText)
  .replace(/@\s*jarvis\b/gi, '')
  .replace(/\s+/g, ' ')
  .trim();

if (!cleanText) {
  return [{ json: { skip: true, reason: 'empty_after_clean', chatId, messageId } }];
}

return [{
  json: {
    skip: false,
    chatId,
    messageId,
    senderName,
    senderPhone,
    rawText,
    cleanText,
    isGroup,
    groupContext: group.context,
    groupLabel: group.label,
    receivedAt: new Date().toISOString()
  }
}];

// ─────────────────────────────────────────────
// Resolve OpenAI thread_id (existing or null = create)
// ─────────────────────────────────────────────
const parsed = $('Parse & Filter Mention').item.json;
const convResp = $input.item.json;
const rows = Array.isArray(convResp) ? convResp : (convResp?.data || []);
const existing = rows.find(r => r && r.wa_chat_id === parsed.chatId);

return [{
  json: {
    ...parsed,
    threadId: existing?.openai_thread_id || null,
    convId: existing?.id || null,
    humorLevel: existing?.humor_level || 50,
    needsThread: !existing?.openai_thread_id
  }
}];

// Merge new threadId back into the data
const meta = $('Resolve Thread').item.json;
const threadResp = $input.item.json;
const threadId = threadResp.id || meta.threadId;
return [{ json: { ...meta, threadId, justCreatedThread: true } }];

// ─────────────────────────────────────────────
// Tool Dispatcher — handles all tool_calls in parallel
// Calls Cockpit API for each, returns tool_outputs array
// ─────────────────────────────────────────────
const run = $input.item.json;
const toolCalls = run.required_action?.submit_tool_outputs?.tool_calls || [];
const COCKPIT = 'https://cockpit.angelfly.io/api';
const TOKEN = '5415d97c31b4ab3198a637234c4a76af86bd3d28ee9ebe9fe9c348f2f2c54c16';

const headers = { 'Authorization': 'Bearer ' + TOKEN, 'Content-Type': 'application/json' };

async function cockpitGet(path) {
  const r = await this.helpers.httpRequest({ method: 'GET',  url: COCKPIT + path, headers, json: true, returnFullResponse: false });
  return r;
}
async function cockpitPost(path, body) {
  const r = await this.helpers.httpRequest({ method: 'POST', url: COCKPIT + path, headers, body, json: true, returnFullResponse: false });
  return r;
}

function normalizeProjectName(name) { return String(name||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim(); }

async function resolveProjectId(projectName) {
  if (!projectName) return null;
  try {
    const projs = await cockpitGet.call(this, '/projects');
    const list = Array.isArray(projs) ? projs : (projs?.data || []);
    const target = normalizeProjectName(projectName);
    const match = list.find(p => normalizeProjectName(p.name) === target)
               || list.find(p => normalizeProjectName(p.name).includes(target))
               || list.find(p => target.includes(normalizeProjectName(p.name)));
    return match?.id || null;
  } catch (e) { return null; }
}
async function resolveUserId(name) {
  if (!name) return null;
  try {
    const users = await cockpitGet.call(this, '/users');
    const list = Array.isArray(users) ? users : (users?.data || []);
    const target = normalizeProjectName(name);
    const match = list.find(u => normalizeProjectName(u.name||u.full_name||u.username) === target)
               || list.find(u => normalizeProjectName(u.name||u.full_name||u.username).includes(target));
    return match?.id || null;
  } catch (e) { return null; }
}

function filterByGroup(items, groupContext) {
  const norm = (v) => normalizeProjectName(v||'');
  return items.filter(it => {
    const blob = norm(it.project_name) + ' ' + norm(it.client_name);
    if (groupContext === 'garlic')   return /garlic|gnl/.test(blob);
    if (groupContext === 'ernesto')  return /ernesto/.test(blob);
    if (groupContext === 'angelfly') return /angel\s*fly|cockpit/.test(blob);
    return true;
  });
}

async function handleTool(call) {
  const name = call.function.name;
  let args = {};
  try { args = JSON.parse(call.function.arguments || '{}'); } catch (e) {}

  try {
    let output;
    switch (name) {
      case 'create_task': {
        const project_id = await resolveProjectId.call(this, args.project_name);
        const assigned_to = await resolveUserId.call(this, args.assigned_to_name);
        const body = {
          title: args.title,
          description: args.description || '',
          project_id, project_name: args.project_name || null,
          priority: args.priority || 'medium',
          status: 'backlog',
          deadline: args.deadline || null,
          assigned_to, assigned_to_name: args.assigned_to_name || null
        };
        const created = await cockpitPost.call(this, '/tasks', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_ticket': {
        const project_id = await resolveProjectId.call(this, args.project_name);
        const body = {
          subject: args.subject,
          description: args.description || '',
          category: args.category || 'bug',
          priority: args.priority || 'medium',
          status: 'open',
          client_name: args.client_name || null,
          project_id, project_name: args.project_name || null
        };
        const created = await cockpitPost.call(this, '/tickets', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_project': {
        const body = {
          name: args.name,
          client_name: args.client_name,
          scope_description: args.scope_description || '',
          status: 'active',
          payment_type: args.payment_type || 'one-time',
          total_budget: args.total_budget || 0
        };
        const created = await cockpitPost.call(this, '/projects', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_payment_incoming': {
        const body = {
          description: args.description || '',
          amount: args.amount,
          client_name: args.client_name,
          status: args.status || 'pending'
        };
        const created = await cockpitPost.call(this, '/payments_incoming', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_payment_outgoing': {
        const body = {
          description: args.description || '',
          amount: args.amount,
          recipient_name: args.recipient_name
        };
        const created = await cockpitPost.call(this, '/payments_outgoing', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'create_quote': {
        const body = {
          title: args.title,
          description: args.description || '',
          client_name: args.client_name,
          amount: args.amount,
          valid_until: args.valid_until || null,
          status: 'draft'
        };
        const created = await cockpitPost.call(this, '/quotes', body);
        output = { success: true, id: created.id || created.data?.id, ...body };
        break;
      }
      case 'list_projects': {
        const projs = await cockpitGet.call(this, '/projects');
        const list = Array.isArray(projs) ? projs : (projs?.data || []);
        output = list.map(p => ({ id: p.id, name: p.name, client_name: p.client_name, status: p.status }));
        break;
      }
      case 'list_users': {
        const users = await cockpitGet.call(this, '/users');
        const list = Array.isArray(users) ? users : (users?.data || []);
        output = list.map(u => ({ id: u.id, name: u.name || u.full_name || u.username, role: u.role }));
        break;
      }
      case 'get_overdue_tasks': {
        const tasks = await cockpitGet.call(this, '/tasks?limit=200');
        const list = Array.isArray(tasks) ? tasks : (tasks?.data || []);
        const today = new Date().toISOString().slice(0,10);
        let overdue = list.filter(t => t.deadline && t.deadline < today && !['done','closed','cancelled'].includes((t.status||'').toLowerCase()));
        if (args.group_context && args.group_context !== 'all') overdue = filterByGroup(overdue, args.group_context);
        output = overdue.map(t => ({ id: t.id, title: t.title, deadline: t.deadline, assigned_to_name: t.assigned_to_name, project_name: t.project_name, priority: t.priority }));
        break;
      }
      case 'get_today_briefing': {
        const [tasksR, ticketsR] = await Promise.all([
          cockpitGet.call(this, '/tasks?limit=200'),
          cockpitGet.call(this, '/tickets?limit=200')
        ]);
        const tasks   = filterByGroup(Array.isArray(tasksR)   ? tasksR   : (tasksR?.data || []),   args.group_context);
        const tickets = filterByGroup(Array.isArray(ticketsR) ? ticketsR : (ticketsR?.data || []), args.group_context);
        const today = new Date().toISOString().slice(0,10);
        const open = (s) => !['done','closed','cancelled','resolved'].includes((s||'').toLowerCase());
        output = {
          today_tasks:   tasks.filter(t => open(t.status) && (t.deadline||'').slice(0,10) === today)
                              .map(t => ({ title: t.title, assigned_to_name: t.assigned_to_name, priority: t.priority })),
          open_tasks:    tasks.filter(t => open(t.status)).length,
          today_tickets: tickets.filter(t => open(t.status) && (t.created_date||t.created_at||'').slice(0,10) === today)
                                .map(t => ({ subject: t.subject, priority: t.priority })),
          open_tickets:  tickets.filter(t => open(t.status)).length
        };
        break;
      }
      default:
        output = { error: 'unknown_tool: ' + name };
    }
    return { tool_call_id: call.id, output: JSON.stringify(output) };
  } catch (err) {
    return { tool_call_id: call.id, output: JSON.stringify({ success: false, error: err.message }) };
  }
}

const results = [];
for (const c of toolCalls) {
  const r = await handleTool.call(this, c);
  results.push(r);
}

return [{ json: { tool_outputs: results, runId: run.id, threadId: run.thread_id } }];

// Extract assistant text from response
const data = $input.item.json;
const messages = data.data || [];
const assistantMsg = messages.find(m => m.role === 'assistant');
let text = '';
if (assistantMsg) {
  const blocks = assistantMsg.content || [];
  text = blocks.filter(b => b.type === 'text').map(b => b.text?.value || '').join('\n').trim();
}
if (!text) text = '🤖 (sem resposta)';

const meta = $('Resolve Thread').item.json;
return [{ json: { ...meta, replyText: text, threadId: $('Merge New Thread').item.json?.threadId || meta.threadId } }];

// Build error reply
const run = $input.item.json;
const meta = $('Parse & Filter Mention').item.json;
let text = '⚠️ Jarvis: deu ruim aqui. ';
if (run.last_error?.message) text += '(' + run.last_error.message + ') ';
text += 'Tenta de novo em 30s.';
return [{ json: { ...meta, replyText: text } }];
